// src/Home.jsx
import React from "react";
import { useNavigate } from "react-router-dom";
import "./Home.css";

export default function Home({ employee }) {
  const navigate = useNavigate();

  return (
    <div
      className="home-container"
      style={{
        minHeight: "100vh",
        background: "linear-gradient(180deg, #e8f5e9 0%, #ffffff 80%)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
      }}
    >
      {/* LOGO */}
      <img
        src="/logo.png"
        alt="PRASA Logo"
        className="home-logo"
        style={{
          width: 110,
          height: 110,
          objectFit: "contain",
          background: "#ffffff",
          borderRadius: 22,
          padding: 12,
          boxShadow: "0 4px 18px rgba(0,0,0,0.12)",
          marginBottom: 18,
        }}
      />

      {/* Company name */}
      <div
        className="home-title"
        style={{ fontSize: 20, fontWeight: 700, color: "#0f9d58", textAlign: "center" }}
      >
        PRASA Infocom & Power Solutions Pvt. Ltd.
      </div>

      {/* Welcome line */}
      <div
        className="home-subtitle"
        style={{
          fontSize: 16,
          color: "#424242",
          marginTop: 8,
          marginBottom: 24,
          textAlign: "center",
        }}
      >
        Welcome to PRASA Employee Portal
        {employee?.name ? `, ${employee.name}` : ""}
      </div>

      {/* Profile button */}
      <div className="home-btn-container" style={{ width: "80%", maxWidth: 320 }}>
        <button
          className="home-btn"
          onClick={() => navigate("/profile")}
          style={{
            backgroundColor: "#0f9d58",
            color: "#ffffff",
            padding: 14,
            borderRadius: 18,
            border: "none",
            fontSize: 16,
            fontWeight: 600,
            width: "100%",
            boxShadow: "0 4px 14px rgba(0,0,0,0.15)",
          }}
        >
          Open Profile
        </button>
      </div>
    </div>
  );
}
